mapper.insert:

insert into ODS_DWEQ_DM_EVENT_D (
id, alarm_id, alarm_type, source_type, monitor_id, device_id, shaft_floor_id, partition_code, partition_name,
data_reference, device_token, partition_no, source_format, event_type, event_time, event_no, event_level,
point_list_json, detail_json, content, merged_flag, deleted, created_on, updated_on
) values (
#{id}, #{alarmId}, #{alarmType}, #{sourceType}, #{monitorId}, #{deviceId}, #{shaftFloorId}, #{partitionCode}, #{partitionName},
#{dataReference}, #{deviceToken}, #{partitionNo}, #{sourceFormat}, #{eventType}, #{eventTime}, #{eventNo}, #{eventLevel},
#{pointListJson}, #{detailJson}, #{content}, #{mergedFlag}, #{deleted}, #{createdOn}, #{updatedOn}
)

mapper.select:
select count(*) from ODS_DWEQ_DM_EVENT_D e join ODS_DWEQ_DM_ALARM_D a on a.id = e.alarm_id left join ODS_DWEQ_DM_DEVICE_D d on d.id = to_number(a.device_id) left join ODS_DWEQ_DM_AREA_D ar on ar.id = d.area_id where (e.deleted is null or e.deleted = 0) and (a.deleted is null or a.deleted = 0) and (d.deleted is null or d.deleted = 0) and (ar.deleted is null or ar.deleted = 0) and a.alarm_type in ('DEVICE_OFFLINE', 'PARTITION_FAULT')
and a.status = #{statusCode}
and ar.name like '%' || #{areaName} || '%'
and d.device_type = #{deviceType}
and e.event_time >= #{startTime}
and e.event_time <= #{endTime}

select * from ( select t.*, row_number() over(order by t.event_time desc, t.event_id desc) rn from ( select a.id as alarm_id, e.id as event_id, a.device_id as device_id, d.name as device_name, ar.name as area_name, d.device_type as device_type, a.alarm_type as alarm_type, a.status as status_code, a.first_alarm_time as first_alarm_time, a.last_alarm_time as last_alarm_time, a.event_count as alarm_count, e.event_no as event_no, e.event_time as event_time, e.event_type as event_type, case when e.content is not null then e.content else a.content end as alarm_content from ODS_DWEQ_DM_EVENT_D e join ODS_DWEQ_DM_ALARM_D a on a.id = e.alarm_id left join ODS_DWEQ_DM_DEVICE_D d on d.id = to_number(a.device_id) left join ODS_DWEQ_DM_AREA_D ar on ar.id = d.area_id where (e.deleted is null or e.deleted = 0) and (a.deleted is null or a.deleted = 0) and (d.deleted is null or d.deleted = 0) and (ar.deleted is null or ar.deleted = 0) and a.alarm_type in ('DEVICE_OFFLINE', 'PARTITION_FAULT')
and a.status = #{statusCode}
and ar.name like '%' || #{areaName} || '%'
and d.device_type = #{deviceType}
and e.event_time >= #{startTime}
and e.event_time <= #{endTime}
) t ) x where x.rn >= #{startRow} and x.rn <= #{endRow} order by x.rn
